module mul_4bit (
    input wire [3:0] A,
    input wire [3:0] B,
    output wire [7:0] result
    );

reg [7:0] unused_product;
integer i;

always@(*) begin
    unused_product = 8'b0;
    for (i = 0; i < 4; i = i + 1) begin
        if (A[i]) begin
            unused_product = unused_product + (B << i);
        end
    end
end

assign result = unused_product;

endmodule
